codeExercises.solution:
const { MongoClient } = require('mongodb');

class MongoDBManager {
  constructor(uri) {
    this.uri = uri;
    this.client = new MongoClient(this.uri, { serverSelectionTimeoutMS: 5000 });
  }

  async connect() {
    try {
      await this.client.connect();
      console.log('Successfully connected to MongoDB Atlas!');
    } catch (error) {
      if (error.message && error.message.includes('SSL alert number 80')) {
        console.error('Connection failed. This might be due to an IP whitelist issue. Please check your Network Access settings in MongoDB Atlas and ensure your current IP is added.');
      } else {
        console.error('An unexpected error occurred during connection:', error);
      }
      throw error;
    }
  }

  async disconnect() {
    await this.client.close();
  }
}
